void load_bpe(char*p){
 FILE*f=fopen(p,"rb");char ln[256];if(!fgets(ln,256,f))return;
 for(int i=0;i<NM;i++){if(!fgets(ln,256,f))break;int n=L(ln);if(n&&ln[n-1]=='\n')n--;ln[n]=0;memcpy(mr[i],ln,n);ml[i]=n;}
